4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill single live cell (underpopulation)", () => {
9	    // Grid: 3x3, center cell (1,1) is alive, no neighbors
10	    const grid: Grid = [
