1	export type Cell = boolean;
2	export type Grid = Cell[][];
3	
4	const countNeighbors = (grid: Grid, row: number, col: number): number => {
5	  let count = 0;
6	  for (let r = row - 1; r <= row + 1; r++) {
7	    for (let c = col - 1; c <= col + 1; c++) {
8	      if (r === row && c === col) continue;
9	      if (r >= 0 && r < grid.length && c >= 0 && c < grid[0].length && grid[r][c]) {
10	        count++;
11	      }
12	    }
13	  }
14	  return count;
15	};
16	
17	const shouldCellBeAlive = (isAlive: boolean, neighbors: number): boolean => {
18	  // Live cells with 2-3 neighbors survive
19	  if (isAlive && (neighbors === 2 || neighbors === 3)) {
20	    return true;
21	  }
22	  // Dead cells with exactly 3 neighbors are born (reproduction)
23	  if (!isAlive && neighbors === 3) {
24	    return true;
25	  }
26	  // All other cells die or stay dead
27	  return false;
28	};
29	
30	export function nextGeneration(grid: Grid): Grid {
31	  if (grid.length === 0) {
32	    return [];
33	  }
34	
35	  return grid.map((row, rowIdx) =>
36	    row.map((cell, colIdx) => {
37	      const neighbors = countNeighbors(grid, rowIdx, colIdx);
38	      return shouldCellBeAlive(cell, neighbors);
39	    })
40	  );
41	}
