  const grid: Grid = [
    [false, false, false],
    [true, false, true],
    [false, false, false],
  ];
  const result = nextGeneration(grid);
  // Center cell should stay dead (dead cell with 2 neighbors = no reproduction)
  expect(result).toEqual([
    [false, false, false],
    [false, false, false],
    [false, false, false],
  ]);
});

